    {
      p_reservation_id: id,
      p_expected_status: currentStatus,
      p_new_status: newStatus,
      p_idempotency_key: buildIdempotencyKey("material-status", [
        id,
        currentStatus,
        newStatus,
      ]),
    },
  );

  if (rpcError) {
    if (rpcError.code === "08000") {
      if (currentStatus === "requested" && newStatus === "reserved") {
        if (reservation.user_id || reservation.child_profile_id) {
          await dispatchNotification(supabase, {
            type: "material",
            title: "Materialreservierung nicht möglich",
            body: "Die Reservierung konnte nicht bestätigt werden, weil aktuell kein Bestand verfügbar ist.",
            payload: {
              reservation_id: id,
              old_status: currentStatus,
              new_status: "cancelled",
              status: "failed",
            },
            recipientUserId: reservation.child_profile_id
              ? null
              : reservation.user_id,
            recipientChildId: reservation.child_profile_id,
            relatedTourId: reservation.tour_id,
            relatedGroupId: null,
          });
        }
      }

      return { error: "Nicht genügend Bestand verfügbar." };
    }

    if (rpcError.code === "40001") {
      return {
        error:
          "Die Reservierung wurde parallel geändert. Bitte Ansicht aktualisieren und erneut versuchen.",
      };
    }

    console.error("RPC update reservation error:", rpcError);
    return { error: "Fehler beim Aktualisieren des Status." };
  }

  let relatedGroupId: string | null = null;
  let relatedTourTitle: string | null = null;
  if (reservation.tour_id) {
    const { data: tourInfo } = await supabase
      .from("tours")
      .select("group, title")
      .eq("id", reservation.tour_id)
      .maybeSingle();

    relatedGroupId = tourInfo?.group ?? null;
    relatedTourTitle = tourInfo?.title ?? null;
  }

  if (
    (newStatus === "reserved" || newStatus === "cancelled") &&
    (reservation.user_id || reservation.child_profile_id)
  ) {
    const title =
      newStatus === "reserved"
        ? "Materialreservierung bestätigt"
        : "Materialreservierung abgelehnt";

    await dispatchNotification(supabase, {
      type: "material",
      title,
      body: relatedTourTitle
        ? `Deine Materialreservierung für "${relatedTourTitle}" wurde ${newStatus === "reserved" ? "bestätigt" : "abgelehnt"}.`
        : `Deine Materialreservierung wurde ${newStatus === "reserved" ? "bestätigt" : "abgelehnt"}.`,
      payload: {
        reservation_id: id,
        old_status: currentStatus,
        new_status: newStatus,
      },
      recipientUserId: reservation.child_profile_id
        ? null
        : reservation.user_id,
      recipientChildId: reservation.child_profile_id,
      relatedTourId: reservation.tour_id,
      relatedGroupId,
    });
  }

  revalidatePath("/admin/material/reservations");
  if (reservation.tour_id) {
    revalidatePath(`/touren/${reservation.tour_id}`);
  }
  return { success: true };
}

"use client";

import { AlertCircle, CheckCircle2, Loader2 } from "lucide-react";
import { useRouter } from "next/navigation";
import type React from "react";
import { useState } from "react";
import { registerForTour } from "@/app/actions/tour-registration";
import { Button } from "@/components/ui/button";

interface Material {
  id: string; // material_type_id
  name: string;
  sizes: string[];
}

interface Child {
  id: string;
  full_name: string;
  birthdate: string;
}

interface TourRegistrationFormProps {
  tourId: string;
  tourStartDate: string;
  minAge: number | null;
  onSuccess?: () => void;
  onCancel?: () => void;
  childrenProfiles: Child[];
  availableMaterials: Material[];
}

export function TourRegistrationForm({
  tourId,
  tourStartDate,
  minAge,
  onSuccess,
  onCancel,
  childrenProfiles,
  availableMaterials,
}: TourRegistrationFormProps) {
  const router = useRouter();
  const [isPending, setIsPending] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [success, setSuccess] = useState<string | null>(null);
  const [selectedChild, setSelectedChild] = useState<string>("self");
  const [selectedMaterials, setSelectedMaterials] = useState<
    Record<string, string>
  >({});

  // Age calculation for selected profile
  let ageTooYoung = false;
  if (minAge && tourStartDate) {
    let birthdate: string | null = null;
    if (selectedChild === "self") {
      // We don't have the user's birthdate here directly in props,
      // but it was checked in the parent component.
      // To be safe, we'll assume the parent check is correct for "self".
    } else {
      const child = childrenProfiles.find((c) => c.id === selectedChild);
      if (child) birthdate = child.birthdate;
    }

    if (birthdate) {
      const bDate = new Date(birthdate);
      const sDate = new Date(tourStartDate);
      let age = sDate.getFullYear() - bDate.getFullYear();
      const m = sDate.getMonth() - bDate.getMonth();
      if (m < 0 || (m === 0 && sDate.getDate() < bDate.getDate())) {
        age--;
      }
      ageTooYoung = age < minAge;
    }
  }

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault();
    setIsPending(true);
    setError(null);

    const formData = new FormData();
    formData.append("tourId", tourId);
    formData.append("childId", selectedChild);

    // Pass materials: material_type_id and selected size
    const materialsData = Object.entries(selectedMaterials).map(
      ([typeId, size]) => ({
        material_type_id: typeId,
        size: size,
      }),
    );
    formData.append("materialsData", JSON.stringify(materialsData));

    const result = await registerForTour(formData);

    setIsPending(false);
    if (result.error) {
      setError(result.error);
    } else if (result.success) {
      setSuccess(result.message || "Erfolgreich angemeldet.");
      // Refresh the page to update tour registrations
      router.refresh();
      if (onSuccess) {
        setTimeout(onSuccess, 2000);
      }
    }
  }

  const toggleMaterial = (typeId: string, defaultSize: string) => {
    setSelectedMaterials((prev) => {
      const copy = { ...prev };
      if (typeId in copy) {
        delete copy[typeId];
      } else {
        copy[typeId] = defaultSize;
      }
      return copy;
    });
  };

  const updateMaterialSize = (typeId: string, size: string) => {
    setSelectedMaterials((prev) => ({
      ...prev,
      [typeId]: size,
    }));
  };

  if (success) {
    return (
      <div className="flex flex-col items-center justify-center py-8 text-center animate-in fade-in zoom-in duration-300">
        <div className="mb-4 rounded-full bg-jdav-green/10 p-3">
          <CheckCircle2 className="h-10 w-10 text-jdav-green" />
        </div>
        <h3 className="text-xl font-bold text-slate-900">Geschafft!</h3>
        <p className="mt-2 text-slate-600">{success}</p>
        <p className="mt-4 text-xs text-slate-400">
          Das Fenster schließt sich automatisch...
        </p>
      </div>
    );
  }

  return (
    <form onSubmit={handleSubmit} className="space-y-6">
      {error && (
        <div className="flex items-center gap-3 rounded-xl bg-red-50 p-4 text-sm text-red-800 border border-red-100">
          <AlertCircle className="h-5 w-5 shrink-0" />
          <p>{error}</p>
        </div>
      )}

      {/* Profile Selection */}
      <div className="space-y-3">
        <p className="text-sm font-semibold text-slate-900">
          Wer soll angemeldet werden?
        </p>
        <div className="grid grid-cols-1 gap-2">
          <button
            type="button"
            onClick={() => setSelectedChild("self")}
            className={`flex items-center justify-between rounded-xl border p-4 text-left transition-all ${
              selectedChild === "self"
                ? "border-jdav-green bg-green-50 ring-1 ring-jdav-green"
                : "border-slate-200 hover:border-slate-300 bg-white"
            }`}
          >
            <span className="font-medium text-slate-900">Ich selbst</span>
            {selectedChild === "self" && (
              <div className="h-2 w-2 rounded-full bg-jdav-green" />
            )}
          </button>

          {childrenProfiles.map((child) => (
            <button
              key={child.id}
              type="button"
              onClick={() => setSelectedChild(child.id)}
              className={`flex items-center justify-between rounded-xl border p-4 text-left transition-all ${
                selectedChild === child.id
                  ? "border-jdav-green bg-green-50 ring-1 ring-jdav-green"
                  : "border-slate-200 hover:border-slate-300 bg-white"
              }`}
            >
              <span className="font-medium text-slate-900">
                {child.full_name}
              </span>
              {selectedChild === child.id && (
                <div className="h-2 w-2 rounded-full bg-jdav-green" />
              )}
            </button>
          ))}
        </div>
      </div>

      {/* Age Warning for Child */}
      {ageTooYoung && (
        <div className="flex items-start gap-3 rounded-xl border border-orange-200 bg-orange-50 p-4">
          <AlertCircle className="h-5 w-5 shrink-0 text-orange-600 mt-0.5" />
          <div>
            <p className="font-bold text-orange-800 text-sm">
              Mindestalter nicht erreicht
            </p>
            <p className="text-xs text-orange-700 mt-1 leading-relaxed">
              Dieser Teilnehmer ist zum Tourstart noch unter {minAge} Jahre alt.
              Die Anmeldung wird als **Ausnahme-Anfrage** markiert und muss vom
              Guide manuell bestätigt werden.
            </p>
          </div>
        </div>
      )}

      {/* Material Selection */}
      {availableMaterials.length > 0 && (
        <div className="space-y-3">
          <p className="text-sm font-semibold text-slate-900">
            Benötigtes Leihmaterial
          </p>
          <div className="grid grid-cols-1 gap-2">
            {availableMaterials.map((material) => {
              const isSelected = material.id in selectedMaterials;

              return (
                <div
                  key={material.id}
                  className={`flex flex-col rounded-xl border p-4 transition-all ${
                    isSelected
                      ? "border-jdav-green bg-green-50"
                      : "border-slate-200 hover:border-slate-300 bg-white"
                  }`}
                >
                  <label className="flex items-center gap-3 cursor-pointer">
                    <input
                      type="checkbox"
                      className="h-5 w-5 rounded border-slate-300 text-jdav-green focus:ring-jdav-green"
                      checked={isSelected}
                      onChange={() =>
                        toggleMaterial(material.id, material.sizes[0])
                      }
                    />
                    <span className="font-medium text-slate-700">
                      {material.name}
                    </span>
                  </label>

                  {isSelected && material.sizes.length > 0 && (
                    <div className="mt-3 ml-8 flex items-center gap-2">
                      <span className="text-xs font-semibold text-slate-600">
                        Größe:
                      </span>
                      <select
                        className="text-sm rounded-lg border-slate-200 py-1 px-2 focus:ring-jdav-green focus:border-jdav-green bg-white shadow-sm"
                        value={
                          selectedMaterials[material.id] || material.sizes[0]
                        }
                        onChange={(e) =>
                          updateMaterialSize(material.id, e.target.value)
                        }
                        required
                      >
                        {material.sizes.map((s) => (
                          <option key={s} value={s}>
                            {s}
                          </option>
                        ))}
                      </select>
                    </div>
                  )}
                </div>
              );
            })}
          </div>
        </div>
      )}

      <div className="flex flex-col gap-3 pt-4 sm:flex-row-reverse">
        <Button
          type="submit"
          disabled={isPending}
          size="lg"
          className="w-full bg-jdav-green hover:bg-jdav-green-dark text-white font-black h-12 rounded-xl shadow-lg shadow-green-900/10"
        >
          {isPending ? (
            <>
              <Loader2 className="mr-2 h-5 w-5 animate-spin" />
              Verarbeiten...
            </>
          ) : (
            "Anmeldung abschicken"
          )}
        </Button>
        <Button
          type="button"
          variant="ghost"
          onClick={onCancel}
          className="w-full text-slate-500 hover:text-slate-900 font-medium"
        >
          Abbrechen
        </Button>
      </div>
    </form>
  );
}

"use client";

import { AlertCircle, CheckCircle2, Loader2 } from "lucide-react";
import { useRouter } from "next/navigation";
import type React from "react";
import { useRef, useState } from "react";
import { registerForTour } from "@/app/actions/tour-registration";
import { Button } from "@/components/ui/button";

interface Material {
  id: string; // material_type_id
  name: string;
  sizes: string[];
}

interface Child {
  id: string;
  full_name: string;
  birthdate: string;
}

interface TourRegistrationFormProps {
  tourId: string;
  tourStartDate: string;
  minAge: number | null;
  onSuccess?: () => void;
  onCancel?: () => void;
  childrenProfiles: Child[];
  availableMaterials: Material[];
}

export function TourRegistrationForm({
  tourId,
  tourStartDate,
  minAge,
  onSuccess,
  onCancel,
  childrenProfiles,
  availableMaterials,
}: TourRegistrationFormProps) {
  const router = useRouter();
  const [isPending, setIsPending] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [success, setSuccess] = useState<string | null>(null);
  const [selectedChild, setSelectedChild] = useState<string>("self");
  const [selectedMaterials, setSelectedMaterials] = useState<
    Record<string, string>
  >({});
  const clientRequestIdRef = useRef<string>(
    typeof crypto !== "undefined" && typeof crypto.randomUUID === "function"
      ? crypto.randomUUID()
      : `${Date.now()}-${Math.random().toString(36).slice(2)}`,
  );

  // Age calculation for selected profile
  let ageTooYoung = false;
  if (minAge && tourStartDate) {
    let birthdate: string | null = null;
    if (selectedChild === "self") {
      // We don't have the user's birthdate here directly in props,
      // but it was checked in the parent component.
      // To be safe, we'll assume the parent check is correct for "self".
    } else {
      const child = childrenProfiles.find((c) => c.id === selectedChild);
      if (child) birthdate = child.birthdate;
    }

    if (birthdate) {
      const bDate = new Date(birthdate);
      const sDate = new Date(tourStartDate);
      let age = sDate.getFullYear() - bDate.getFullYear();
      const m = sDate.getMonth() - bDate.getMonth();
      if (m < 0 || (m === 0 && sDate.getDate() < bDate.getDate())) {
        age--;
      }
      ageTooYoung = age < minAge;
    }
  }

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault();
    setIsPending(true);
    setError(null);

    const formData = new FormData();
    formData.append("tourId", tourId);
    formData.append("childId", selectedChild);
    formData.append("clientRequestId", clientRequestIdRef.current);

    // Pass materials: material_type_id and selected size
    const materialsData = Object.entries(selectedMaterials).map(
      ([typeId, size]) => ({
        material_type_id: typeId,
        size: size,
      }),
    );
    formData.append("materialsData", JSON.stringify(materialsData));

    const result = await registerForTour(formData);

    setIsPending(false);
    if (result.error) {
      setError(result.error);
    } else if (result.success) {
      setSuccess(result.message || "Erfolgreich angemeldet.");
      // Refresh the page to update tour registrations
      router.refresh();
      if (onSuccess) {
        setTimeout(onSuccess, 2000);
      }
    }
  }

  const toggleMaterial = (typeId: string, defaultSize: string) => {
    setSelectedMaterials((prev) => {
      const copy = { ...prev };
      if (typeId in copy) {
        delete copy[typeId];
      } else {
        copy[typeId] = defaultSize;
      }
      return copy;
    });
  };

  const updateMaterialSize = (typeId: string, size: string) => {
    setSelectedMaterials((prev) => ({
      ...prev,
      [typeId]: size,
    }));
  };

  if (success) {
    return (
      <div className="flex flex-col items-center justify-center py-8 text-center animate-in fade-in zoom-in duration-300">
        <div className="mb-4 rounded-full bg-jdav-green/10 p-3">
          <CheckCircle2 className="h-10 w-10 text-jdav-green" />
        </div>
        <h3 className="text-xl font-bold text-slate-900">Geschafft!</h3>
        <p className="mt-2 text-slate-600">{success}</p>
        <p className="mt-4 text-xs text-slate-400">
          Das Fenster schließt sich automatisch...
        </p>
      </div>
    );
  }

  return (
    <form onSubmit={handleSubmit} className="space-y-6">
      {error && (
        <div className="flex items-center gap-3 rounded-xl bg-red-50 p-4 text-sm text-red-800 border border-red-100">
          <AlertCircle className="h-5 w-5 shrink-0" />
          <p>{error}</p>
        </div>
      )}

      {/* Profile Selection */}
      <div className="space-y-3">
        <p className="text-sm font-semibold text-slate-900">
          Wer soll angemeldet werden?
        </p>
        <div className="grid grid-cols-1 gap-2">
          <button
            type="button"
            onClick={() => setSelectedChild("self")}
            className={`flex items-center justify-between rounded-xl border p-4 text-left transition-all ${
              selectedChild === "self"
                ? "border-jdav-green bg-green-50 ring-1 ring-jdav-green"
                : "border-slate-200 hover:border-slate-300 bg-white"
            }`}
          >
            <span className="font-medium text-slate-900">Ich selbst</span>
            {selectedChild === "self" && (
              <div className="h-2 w-2 rounded-full bg-jdav-green" />
            )}
          </button>

          {childrenProfiles.map((child) => (
            <button
              key={child.id}
              type="button"
              onClick={() => setSelectedChild(child.id)}
              className={`flex items-center justify-between rounded-xl border p-4 text-left transition-all ${
                selectedChild === child.id
                  ? "border-jdav-green bg-green-50 ring-1 ring-jdav-green"
                  : "border-slate-200 hover:border-slate-300 bg-white"
              }`}
            >
              <span className="font-medium text-slate-900">
                {child.full_name}
              </span>
              {selectedChild === child.id && (
                <div className="h-2 w-2 rounded-full bg-jdav-green" />
              )}
            </button>
          ))}
        </div>
      </div>

      {/* Age Warning for Child */}
      {ageTooYoung && (
        <div className="flex items-start gap-3 rounded-xl border border-orange-200 bg-orange-50 p-4">
          <AlertCircle className="h-5 w-5 shrink-0 text-orange-600 mt-0.5" />
          <div>
            <p className="font-bold text-orange-800 text-sm">
              Mindestalter nicht erreicht
            </p>
            <p className="text-xs text-orange-700 mt-1 leading-relaxed">
              Dieser Teilnehmer ist zum Tourstart noch unter {minAge} Jahre alt.
              Die Anmeldung wird als **Ausnahme-Anfrage** markiert und muss vom
              Guide manuell bestätigt werden.
            </p>
          </div>
        </div>
      )}

      {/* Material Selection */}
      {availableMaterials.length > 0 && (
        <div className="space-y-3">
          <p className="text-sm font-semibold text-slate-900">
            Benötigtes Leihmaterial
          </p>
          <div className="grid grid-cols-1 gap-2">
            {availableMaterials.map((material) => {
              const isSelected = material.id in selectedMaterials;

              return (
                <div
                  key={material.id}
                  className={`flex flex-col rounded-xl border p-4 transition-all ${
                    isSelected
                      ? "border-jdav-green bg-green-50"
                      : "border-slate-200 hover:border-slate-300 bg-white"
                  }`}
                >
                  <label className="flex items-center gap-3 cursor-pointer">
                    <input
                      type="checkbox"
                      className="h-5 w-5 rounded border-slate-300 text-jdav-green focus:ring-jdav-green"
                      checked={isSelected}
                      onChange={() =>
                        toggleMaterial(material.id, material.sizes[0])
                      }
                    />
                    <span className="font-medium text-slate-700">
                      {material.name}
                    </span>
                  </label>

                  {isSelected && material.sizes.length > 0 && (
                    <div className="mt-3 ml-8 flex items-center gap-2">
                      <span className="text-xs font-semibold text-slate-600">
                        Größe:
                      </span>
                      <select
                        className="text-sm rounded-lg border-slate-200 py-1 px-2 focus:ring-jdav-green focus:border-jdav-green bg-white shadow-sm"
                        value={
                          selectedMaterials[material.id] || material.sizes[0]
                        }
                        onChange={(e) =>
                          updateMaterialSize(material.id, e.target.value)
                        }
                        required
                      >
                        {material.sizes.map((s) => (
                          <option key={s} value={s}>
                            {s}
                          </option>
                        ))}
                      </select>
                    </div>
                  )}
                </div>
              );
            })}
          </div>
        </div>
      )}

      <div className="flex flex-col gap-3 pt-4 sm:flex-row-reverse">
        <Button
          type="submit"
          disabled={isPending}
          size="lg"
          className="w-full bg-jdav-green hover:bg-jdav-green-dark text-white font-black h-12 rounded-xl shadow-lg shadow-green-900/10"
        >
          {isPending ? (
            <>
              <Loader2 className="mr-2 h-5 w-5 animate-spin" />
              Verarbeiten...
            </>
          ) : (
            "Anmeldung abschicken"
          )}
        </Button>
        <Button
          type="button"
          variant="ghost"
          onClick={onCancel}
          className="w-full text-slate-500 hover:text-slate-900 font-medium"
        >
          Abbrechen
        </Button>
      </div>
    </form>
  );
}

import { createHash } from "node:crypto";

export function buildIdempotencyKey(
  scope: string,
  parts: Array<string | number | null | undefined>,
): string {
  const normalized = parts.map((part) => String(part ?? "")).join("|");
  return `${scope}:${createHash("sha256").update(normalized).digest("hex")}`;
}

-- P2.1: Atomic mutation wrappers for participant/material status transitions
-- Goal: move critical write paths from app-level multi-step writes into transactional RPCs.

BEGIN;

CREATE OR REPLACE FUNCTION public.apply_participant_status_transition_atomic(
  p_registration_id UUID,
  p_expected_status public.participant_status,
  p_new_status public.participant_status
)
RETURNS JSONB
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = 'public', 'pg_temp'
AS $$
DECLARE
  v_reg RECORD;
  v_promotion JSONB;
  v_promoted_count INTEGER := 0;
BEGIN
  IF p_registration_id IS NULL THEN
    RAISE EXCEPTION 'p_registration_id is required';
  END IF;

  SELECT id, tour_id, user_id, child_profile_id, status
  INTO v_reg
  FROM public.tour_participants
  WHERE id = p_registration_id
  FOR UPDATE;

  IF v_reg IS NULL THEN
    RAISE EXCEPTION 'Registration not found' USING ERRCODE = '02000';
  END IF;

  IF v_reg.status IS DISTINCT FROM p_expected_status THEN
    RAISE EXCEPTION 'Registration status changed concurrently' USING ERRCODE = '40001';
  END IF;

  IF v_reg.status IS DISTINCT FROM p_new_status THEN
    UPDATE public.tour_participants
    SET status = p_new_status
    WHERE id = p_registration_id;
  END IF;

  -- Keep waitlist promotion and status sync in the same transaction boundary.
  IF p_new_status = 'cancelled'::public.participant_status
     AND p_expected_status IN ('pending'::public.participant_status, 'confirmed'::public.participant_status) THEN
    SELECT public.promote_first_waitlist(v_reg.tour_id) INTO v_promotion;
    v_promoted_count := COALESCE((v_promotion->>'promoted_count')::INTEGER, 0);
  ELSE
    PERFORM public.sync_tour_status_explicit(v_reg.tour_id);
  END IF;

  RETURN jsonb_build_object(
    'success', true,
    'tour_id', v_reg.tour_id,
    'participant_user_id', v_reg.user_id,
    'participant_child_id', v_reg.child_profile_id,
    'old_status', p_expected_status,
    'new_status', p_new_status,
    'promoted_count', v_promoted_count,
    'promoted_user_id', CASE WHEN v_promoted_count > 0 THEN v_promotion->>'promoted_user_id' ELSE NULL END,
    'promoted_child_id', CASE WHEN v_promoted_count > 0 THEN v_promotion->>'promoted_child_id' ELSE NULL END
  );
END;
$$;

CREATE OR REPLACE FUNCTION public.apply_material_reservation_transition_atomic(
  p_reservation_id UUID,
  p_expected_status TEXT,
  p_new_status TEXT
)
RETURNS JSONB
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = 'public', 'pg_temp'
AS $$
DECLARE
  v_res RECORD;
  v_inventory RECORD;
  v_delta INTEGER := 0;
  v_qty INTEGER := 1;
BEGIN
  IF p_reservation_id IS NULL THEN
    RAISE EXCEPTION 'p_reservation_id is required';
  END IF;

  SELECT id, status, quantity, tour_id, user_id, child_profile_id, material_inventory_id
  INTO v_res
  FROM public.material_reservations
  WHERE id = p_reservation_id
  FOR UPDATE;

  IF v_res IS NULL THEN
    RAISE EXCEPTION 'Reservation not found' USING ERRCODE = '02000';
  END IF;

  IF COALESCE(v_res.status, 'requested') IS DISTINCT FROM p_expected_status THEN
    RAISE EXCEPTION 'Reservation status changed concurrently' USING ERRCODE = '40001';
  END IF;

  v_qty := GREATEST(COALESCE(v_res.quantity, 1), 1);

  -- Inventory movement rules: reserve consumes stock, returned/cancelled from active gives it back.
  IF p_expected_status = 'requested' AND p_new_status = 'reserved' THEN
    v_delta := -v_qty;
  ELSIF p_expected_status IN ('reserved', 'on loan') AND p_new_status IN ('returned', 'cancelled') THEN
    v_delta := v_qty;
  END IF;

  IF v_delta <> 0 THEN
    SELECT id, quantity_available
    INTO v_inventory
    FROM public.material_inventory
    WHERE id = v_res.material_inventory_id
    FOR UPDATE;

    IF v_inventory IS NULL THEN
      RAISE EXCEPTION 'Material inventory not found' USING ERRCODE = '02000';
    END IF;

    IF v_inventory.quantity_available + v_delta < 0 THEN
      RAISE EXCEPTION 'Insufficient inventory' USING ERRCODE = '08000';
    END IF;

    UPDATE public.material_inventory
    SET quantity_available = quantity_available + v_delta
    WHERE id = v_res.material_inventory_id;
  END IF;

  UPDATE public.material_reservations
  SET status = p_new_status
  WHERE id = p_reservation_id;

  RETURN jsonb_build_object(
    'success', true,
    'reservation_id', p_reservation_id,
    'tour_id', v_res.tour_id,
    'user_id', v_res.user_id,
    'child_profile_id', v_res.child_profile_id,
    'old_status', p_expected_status,
    'new_status', p_new_status,
    'inventory_delta', v_delta
  );
END;
$$;

CREATE OR REPLACE FUNCTION public.cancel_own_private_material_reservation_atomic(
  p_reservation_id UUID,
  p_user_id UUID
)
RETURNS JSONB
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = 'public', 'pg_temp'
AS $$
DECLARE
  v_res RECORD;
  v_inventory RECORD;
  v_qty INTEGER := 1;
BEGIN
  IF p_reservation_id IS NULL OR p_user_id IS NULL THEN
    RAISE EXCEPTION 'p_reservation_id and p_user_id are required';
  END IF;

  SELECT id, user_id, tour_id, status, quantity, material_inventory_id
  INTO v_res
  FROM public.material_reservations
  WHERE id = p_reservation_id
  FOR UPDATE;

  IF v_res IS NULL THEN
    RAISE EXCEPTION 'Reservation not found' USING ERRCODE = '02000';
  END IF;

  IF v_res.user_id IS DISTINCT FROM p_user_id OR v_res.tour_id IS NOT NULL THEN
    RAISE EXCEPTION 'Forbidden' USING ERRCODE = '42501';
  END IF;

  IF v_res.status IN ('cancelled', 'returned') THEN
    RAISE EXCEPTION 'Reservation cannot be cancelled' USING ERRCODE = '23514';
  END IF;

  v_qty := GREATEST(COALESCE(v_res.quantity, 1), 1);

  IF v_res.status IN ('reserved', 'on loan') THEN
    SELECT id, quantity_available
    INTO v_inventory
    FROM public.material_inventory
    WHERE id = v_res.material_inventory_id
    FOR UPDATE;

    IF v_inventory IS NULL THEN
      RAISE EXCEPTION 'Material inventory not found' USING ERRCODE = '02000';
    END IF;

    UPDATE public.material_inventory
    SET quantity_available = quantity_available + v_qty
    WHERE id = v_res.material_inventory_id;
  END IF;

  UPDATE public.material_reservations
  SET status = 'cancelled'
  WHERE id = p_reservation_id;

  RETURN jsonb_build_object(
    'success', true,
    'reservation_id', p_reservation_id,
    'old_status', v_res.status,
    'new_status', 'cancelled'
  );
END;
$$;

COMMIT;

-- P2.1: Atomic mutation wrappers for participant/material status transitions
-- Goal: move critical write paths from app-level multi-step writes into transactional RPCs.

BEGIN;

CREATE TABLE IF NOT EXISTS public.mutation_idempotency (
  scope TEXT NOT NULL,
  idempotency_key TEXT NOT NULL,
  response JSONB NOT NULL,
  created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  PRIMARY KEY (scope, idempotency_key)
);

CREATE OR REPLACE FUNCTION public.store_mutation_idempotency_response(
  p_scope TEXT,
  p_idempotency_key TEXT,
  p_response JSONB
)
RETURNS VOID
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = 'public', 'pg_temp'
AS $$
BEGIN
  IF p_idempotency_key IS NULL OR LENGTH(TRIM(p_idempotency_key)) = 0 THEN
    RETURN;
  END IF;

  INSERT INTO public.mutation_idempotency (scope, idempotency_key, response)
  VALUES (p_scope, p_idempotency_key, p_response)
  ON CONFLICT (scope, idempotency_key)
  DO NOTHING;
END;
$$;

CREATE OR REPLACE FUNCTION public.apply_participant_status_transition_atomic(
  p_registration_id UUID,
  p_expected_status public.participant_status,
  p_new_status public.participant_status,
  p_idempotency_key TEXT DEFAULT NULL
)
RETURNS JSONB
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = 'public', 'pg_temp'
AS $$
DECLARE
  v_reg RECORD;
  v_promotion JSONB;
  v_promoted_count INTEGER := 0;
  v_cached_response JSONB;
  v_result JSONB;
BEGIN
      IF p_idempotency_key IS NOT NULL AND LENGTH(TRIM(p_idempotency_key)) > 0 THEN
        SELECT response
        INTO v_cached_response
        FROM public.mutation_idempotency
        WHERE scope = 'participant_status_transition'
          AND idempotency_key = p_idempotency_key;

        IF v_cached_response IS NOT NULL THEN
          RETURN v_cached_response;
        END IF;
      END IF;

  IF p_registration_id IS NULL THEN
    RAISE EXCEPTION 'p_registration_id is required';
  END IF;

  SELECT id, tour_id, user_id, child_profile_id, status
  INTO v_reg
  FROM public.tour_participants
  WHERE id = p_registration_id
  FOR UPDATE;

  IF v_reg IS NULL THEN
    RAISE EXCEPTION 'Registration not found' USING ERRCODE = '02000';
  END IF;

  IF v_reg.status IS DISTINCT FROM p_expected_status THEN
    RAISE EXCEPTION 'Registration status changed concurrently' USING ERRCODE = '40001';
  END IF;

  IF v_reg.status IS DISTINCT FROM p_new_status THEN
    UPDATE public.tour_participants
    SET status = p_new_status
    WHERE id = p_registration_id;
  END IF;

  -- Keep waitlist promotion and status sync in the same transaction boundary.
  IF p_new_status = 'cancelled'::public.participant_status
     AND p_expected_status IN ('pending'::public.participant_status, 'confirmed'::public.participant_status) THEN
    SELECT public.promote_first_waitlist(v_reg.tour_id) INTO v_promotion;
    v_promoted_count := COALESCE((v_promotion->>'promoted_count')::INTEGER, 0);
  ELSE
    PERFORM public.sync_tour_status_explicit(v_reg.tour_id);
  END IF;

  v_result := jsonb_build_object(
    'success', true,
    'tour_id', v_reg.tour_id,
    'participant_user_id', v_reg.user_id,
    'participant_child_id', v_reg.child_profile_id,
    'old_status', p_expected_status,
    'new_status', p_new_status,
    'promoted_count', v_promoted_count,
    'promoted_user_id', CASE WHEN v_promoted_count > 0 THEN v_promotion->>'promoted_user_id' ELSE NULL END,
    'promoted_child_id', CASE WHEN v_promoted_count > 0 THEN v_promotion->>'promoted_child_id' ELSE NULL END
  );

  PERFORM public.store_mutation_idempotency_response(
    'participant_status_transition',
    p_idempotency_key,
    v_result
  );

  RETURN v_result;
END;
$$;

CREATE OR REPLACE FUNCTION public.apply_material_reservation_transition_atomic(
  p_reservation_id UUID,
  p_expected_status TEXT,
  p_new_status TEXT,
  p_idempotency_key TEXT DEFAULT NULL
)
RETURNS JSONB
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = 'public', 'pg_temp'
AS $$
DECLARE
  v_res RECORD;
  v_inventory RECORD;
  v_delta INTEGER := 0;
  v_qty INTEGER := 1;
  v_cached_response JSONB;
  v_result JSONB;
BEGIN
      IF p_idempotency_key IS NOT NULL AND LENGTH(TRIM(p_idempotency_key)) > 0 THEN
        SELECT response
        INTO v_cached_response
        FROM public.mutation_idempotency
        WHERE scope = 'material_reservation_transition'
          AND idempotency_key = p_idempotency_key;

        IF v_cached_response IS NOT NULL THEN
          RETURN v_cached_response;
        END IF;
      END IF;

  IF p_reservation_id IS NULL THEN
    RAISE EXCEPTION 'p_reservation_id is required';
  END IF;

  SELECT id, status, quantity, tour_id, user_id, child_profile_id, material_inventory_id
  INTO v_res
  FROM public.material_reservations
  WHERE id = p_reservation_id
  FOR UPDATE;

  IF v_res IS NULL THEN
    RAISE EXCEPTION 'Reservation not found' USING ERRCODE = '02000';
  END IF;

  IF COALESCE(v_res.status, 'requested') IS DISTINCT FROM p_expected_status THEN
    RAISE EXCEPTION 'Reservation status changed concurrently' USING ERRCODE = '40001';
  END IF;

  v_qty := GREATEST(COALESCE(v_res.quantity, 1), 1);

  -- Inventory movement rules: reserve consumes stock, returned/cancelled from active gives it back.
  IF p_expected_status = 'requested' AND p_new_status = 'reserved' THEN
    v_delta := -v_qty;
  ELSIF p_expected_status IN ('reserved', 'on loan') AND p_new_status IN ('returned', 'cancelled') THEN
    v_delta := v_qty;
  END IF;

  IF v_delta <> 0 THEN
    SELECT id, quantity_available
    INTO v_inventory
    FROM public.material_inventory
    WHERE id = v_res.material_inventory_id
    FOR UPDATE;

    IF v_inventory IS NULL THEN
      RAISE EXCEPTION 'Material inventory not found' USING ERRCODE = '02000';
    END IF;

    IF v_inventory.quantity_available + v_delta < 0 THEN
      RAISE EXCEPTION 'Insufficient inventory' USING ERRCODE = '08000';
    END IF;

    UPDATE public.material_inventory
    SET quantity_available = quantity_available + v_delta
    WHERE id = v_res.material_inventory_id;
  END IF;

  UPDATE public.material_reservations
  SET status = p_new_status
  WHERE id = p_reservation_id;

  v_result := jsonb_build_object(
    'success', true,
    'reservation_id', p_reservation_id,
    'tour_id', v_res.tour_id,
    'user_id', v_res.user_id,
    'child_profile_id', v_res.child_profile_id,
    'old_status', p_expected_status,
    'new_status', p_new_status,
    'inventory_delta', v_delta
  );

  PERFORM public.store_mutation_idempotency_response(
    'material_reservation_transition',
    p_idempotency_key,
    v_result
  );

  RETURN v_result;
END;
$$;

CREATE OR REPLACE FUNCTION public.cancel_own_private_material_reservation_atomic(
  p_reservation_id UUID,
  p_user_id UUID,
  p_idempotency_key TEXT DEFAULT NULL
)
RETURNS JSONB
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = 'public', 'pg_temp'
AS $$
DECLARE
  v_res RECORD;
  v_inventory RECORD;
  v_qty INTEGER := 1;
  v_cached_response JSONB;
  v_result JSONB;
BEGIN
      IF p_idempotency_key IS NOT NULL AND LENGTH(TRIM(p_idempotency_key)) > 0 THEN
        SELECT response
        INTO v_cached_response
        FROM public.mutation_idempotency
        WHERE scope = 'cancel_private_material_reservation'
          AND idempotency_key = p_idempotency_key;

        IF v_cached_response IS NOT NULL THEN
          RETURN v_cached_response;
        END IF;
      END IF;

  IF p_reservation_id IS NULL OR p_user_id IS NULL THEN
    RAISE EXCEPTION 'p_reservation_id and p_user_id are required';
  END IF;

  SELECT id, user_id, tour_id, status, quantity, material_inventory_id
  INTO v_res
  FROM public.material_reservations
  WHERE id = p_reservation_id
  FOR UPDATE;

  IF v_res IS NULL THEN
    RAISE EXCEPTION 'Reservation not found' USING ERRCODE = '02000';
  END IF;

  IF v_res.user_id IS DISTINCT FROM p_user_id OR v_res.tour_id IS NOT NULL THEN
    RAISE EXCEPTION 'Forbidden' USING ERRCODE = '42501';
  END IF;

  IF v_res.status IN ('cancelled', 'returned') THEN
    RAISE EXCEPTION 'Reservation cannot be cancelled' USING ERRCODE = '23514';
  END IF;

  v_qty := GREATEST(COALESCE(v_res.quantity, 1), 1);

  IF v_res.status IN ('reserved', 'on loan') THEN
    SELECT id, quantity_available
    INTO v_inventory
    FROM public.material_inventory
    WHERE id = v_res.material_inventory_id
    FOR UPDATE;

    IF v_inventory IS NULL THEN
      RAISE EXCEPTION 'Material inventory not found' USING ERRCODE = '02000';
    END IF;

    UPDATE public.material_inventory
    SET quantity_available = quantity_available + v_qty
    WHERE id = v_res.material_inventory_id;
  END IF;

  UPDATE public.material_reservations
  SET status = 'cancelled'
  WHERE id = p_reservation_id;

  v_result := jsonb_build_object(
    'success', true,
    'reservation_id', p_reservation_id,
    'old_status', v_res.status,
    'new_status', 'cancelled'
  );

  PERFORM public.store_mutation_idempotency_response(
    'cancel_private_material_reservation',
    p_idempotency_key,
    v_result
  );

  RETURN v_result;
END;
$$;

COMMIT;

-- P2.2: Make register_for_tour_atomic idempotent for safe retries/double-submit.

BEGIN;

CREATE OR REPLACE FUNCTION public.register_for_tour_atomic(
  p_tour_id UUID,
  p_user_id UUID,
  p_child_id UUID,
  p_materials JSONB DEFAULT NULL,
  p_idempotency_key TEXT DEFAULT NULL
)
RETURNS JSONB
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = 'public', 'pg_temp'
AS $$
DECLARE
  v_tour RECORD;
  v_confirmed_count INTEGER;
  v_participant_id UUID;
  v_status public.participant_status;
  v_waitlist_pos INTEGER := NULL;
  v_material JSONB;
  v_inventory RECORD;
  v_res_id UUID;
  v_cached_response JSONB;
  v_result JSONB;
BEGIN
  IF p_idempotency_key IS NOT NULL AND LENGTH(TRIM(p_idempotency_key)) > 0 THEN
    SELECT response
    INTO v_cached_response
    FROM public.mutation_idempotency
    WHERE scope = 'register_for_tour'
      AND idempotency_key = p_idempotency_key;

    IF v_cached_response IS NOT NULL THEN
      RETURN jsonb_set(v_cached_response, '{idempotency_replayed}', 'true'::jsonb, true);
    END IF;
  END IF;

  PERFORM 1
  FROM public.tour_participants
  WHERE tour_id = p_tour_id
    AND user_id = p_user_id
    AND (
      (p_child_id IS NULL AND child_profile_id IS NULL)
      OR (p_child_id IS NOT NULL AND child_profile_id = p_child_id)
    )
    AND status IN (
      'pending'::public.participant_status,
      'confirmed'::public.participant_status,
      'waitlist'::public.participant_status
    )
  LIMIT 1;

  IF FOUND THEN
    RAISE EXCEPTION 'Already registered for this tour' USING ERRCODE = '23505';
  END IF;

  SELECT id, max_participants, status, created_by
  INTO v_tour
  FROM public.tours
  WHERE id = p_tour_id
  FOR UPDATE;

  IF v_tour IS NULL THEN
    RAISE EXCEPTION 'Tour not found' USING ERRCODE = '02000';
  END IF;

  SELECT COUNT(*)
  INTO v_confirmed_count
  FROM public.tour_participants
  WHERE tour_id = p_tour_id
    AND status IN (
      'confirmed'::public.participant_status,
      'pending'::public.participant_status
    );

  IF v_tour.max_participants IS NOT NULL
     AND v_confirmed_count >= v_tour.max_participants THEN
    v_status := 'waitlist'::public.participant_status;

    SELECT COALESCE(MAX(waitlist_position), 0) + 1
    INTO v_waitlist_pos
    FROM public.tour_participants
    WHERE tour_id = p_tour_id
      AND status = 'waitlist'::public.participant_status;
  ELSE
    v_status := 'pending'::public.participant_status;
  END IF;

  INSERT INTO public.tour_participants (
    tour_id, user_id, child_profile_id, status, waitlist_position, created_at
  ) VALUES (
    p_tour_id, p_user_id, p_child_id, v_status, v_waitlist_pos, NOW()
  ) RETURNING id INTO v_participant_id;

  IF p_materials IS NOT NULL THEN
    FOR v_material IN SELECT * FROM jsonb_array_elements(p_materials)
    LOOP
      SELECT id, quantity_available
      INTO v_inventory
      FROM public.material_inventory
      WHERE id = (v_material->>'material_inventory_id')::UUID
        AND quantity_available > 0
      FOR UPDATE;

      IF v_inventory IS NULL THEN
        DELETE FROM public.tour_participants WHERE id = v_participant_id;
        RAISE EXCEPTION 'Material not available: %', v_material->>'material_type_id'
          USING ERRCODE = '08000';
      END IF;

      INSERT INTO public.material_reservations (
        tour_id,
        material_inventory_id,
        user_id,
        child_profile_id,
        quantity,
        status,
        loan_date,
        return_date,
        created_at
      ) VALUES (
        p_tour_id,
        (v_material->>'material_inventory_id')::UUID,
        p_user_id,
        p_child_id,
        COALESCE(NULLIF(v_material->>'quantity', '')::INTEGER, 1),
        'reserved',
        (SELECT start_date FROM public.tours WHERE id = p_tour_id),
        (SELECT end_date FROM public.tours WHERE id = p_tour_id),
        NOW()
      )
      RETURNING id INTO v_res_id;

      UPDATE public.material_inventory
      SET quantity_available = quantity_available - COALESCE(NULLIF(v_material->>'quantity', '')::INTEGER, 1)
      WHERE id = (v_material->>'material_inventory_id')::UUID;
    END LOOP;
  END IF;

  IF v_tour.max_participants IS NOT NULL
     AND v_confirmed_count + 1 >= v_tour.max_participants
     AND v_tour.status IS DISTINCT FROM 'full'::public.tour_status THEN
    UPDATE public.tours
    SET status = 'full'::public.tour_status
    WHERE id = p_tour_id;
  END IF;

  v_result := jsonb_build_object(
    'success', true,
    'participant_id', v_participant_id,
    'status', v_status,
    'waitlist_position', v_waitlist_pos,
    'tour_id', p_tour_id,
    'idempotency_replayed', false
  );

  PERFORM public.store_mutation_idempotency_response(
    'register_for_tour',
    p_idempotency_key,
    v_result
  );

  RETURN v_result;
END;
$$;

COMMIT;
